func trackRequest(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "anonymous"
	}

	endpoint := r.URL.Query().Get("endpoint")
	if endpoint == "" {
		endpoint = r.URL.Path
	}

	method := r.Method
	userAgent := r.Header.Get("User-Agent")
	if userAgent == "" {
		userAgent = "unknown"
	}
	ipAddress := r.RemoteAddr

	requestID := generateRequestID()
	sessionID := r.URL.Query().Get("session_id")
	if sessionID == "" {
		sessionID = "no_session"
	}

	activeRequests.WithLabelValues(userID, endpoint, sessionID).Inc()
	defer activeRequests.WithLabelValues(userID, endpoint, sessionID).Dec()

	start := time.Now()

	status := "200"

	requestCounter.WithLabelValues(userID, endpoint, method, status, userAgent, ipAddress).Inc()

	duration := time.Since(start).Seconds()
	requestDuration.WithLabelValues(userID, endpoint, method, status, requestID).Observe(duration)

	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Request tracked"))
}

func recordOperation(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	operationType := r.URL.Query().Get("operation_type")
	resourceID := r.URL.Query().Get("resource_id")
	teamID := r.URL.Query().Get("team_id")
	projectID := r.URL.Query().Get("project_id")

	if userID == "" {
		userID = "unknown"
	}
	if operationType == "" {
		operationType = "unknown"
	}
	if resourceID == "" {
		resourceID = "none"
	}
	if teamID == "" {
		teamID = "default"
	}
	if projectID == "" {
		projectID = "default"
	}

	userOperations.WithLabelValues(userID, operationType, resourceID, teamID, projectID).Inc()

	bytes := rand.Intn(10000) + 100
	dataType := r.URL.Query().Get("data_type")
	if dataType == "" {
		dataType = "generic"
	}
	operation := r.URL.Query().Get("operation")
	if operation == "" {
		operation = "process"
	}
	tenantID := r.URL.Query().Get("tenant_id")
	if tenantID == "" {
		tenantID = "default_tenant"
	}

	dataProcessed.WithLabelValues(userID, dataType, operation, tenantID).Add(float64(bytes))

	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Operation recorded"))
}

func recordAPICall(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	apiEndpoint := r.URL.Query().Get("api_endpoint")
	version := r.URL.Query().Get("version")
	region := r.URL.Query().Get("region")
	deviceType := r.URL.Query().Get("device_type")

	if userID == "" {
		userID = "unknown"
	}
	if apiEndpoint == "" {
		apiEndpoint = "/api/default"
	}
	if version == "" {
		version = "v1"
	}
	if region == "" {
		region = "us-east-1"
	}
	if deviceType == "" {
		deviceType = "web"
	}

	start := time.Now()

	time.Sleep(time.Duration(rand.Intn(100)) * time.Millisecond)

	latency := time.Since(start).Seconds()
	apiLatency.WithLabelValues(userID, apiEndpoint, version, region, deviceType).Observe(latency)

	w.WriteHeader(http.StatusOK)
	w.Write([]byte("API call recorded"))
}

func recordCustomMetric(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	metricName := r.URL.Query().Get("metric_name")
	dimension1 := r.URL.Query().Get("dimension1")
	dimension2 := r.URL.Query().Get("dimension2")
	dimension3 := r.URL.Query().Get("dimension3")
	value := r.URL.Query().Get("value")

	if userID == "" {
		userID = "unknown"
	}
	if metricName == "" {
		metricName = "default_metric"
	}
	if dimension1 == "" {
		dimension1 = "dim1"
	}
	if dimension2 == "" {
		dimension2 = "dim2"
	}
	if dimension3 == "" {
		dimension3 = "dim3"
	}

	metricValue := 1.0
	if value != "" {
		if v, err := time.ParseDuration(value); err == nil {
			metricValue = v.Seconds()
		}
	}

	customMetric.WithLabelValues(userID, metricName, dimension1, dimension2, dimension3).Set(metricValue)

	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Custom metric recorded"))
}

func generateRequestID() string {
	const charset = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, 16)
	for i := range b {
		b[i] = charset[rand.Intn(len(charset))]
	}
	return string(b)
}

